views.css:
.sp-card {
  --nat-ink:    #1e1508;
  --nat-ink2:   #5c4a2c;
  --nat-muted:  #8c7a5a;
  --nat-faint:  #b5a47a;
  --nat-paper:  #f4eed7;
  --nat-paper2: #e8dfc4;
  --nat-border: #c4aa7a;
  --nat-green:  #3d5c35;
  --nat-serif:  'Palatino Linotype', Palatino, 'Book Antiqua', Georgia, serif;

  display: flex;
  align-items: stretch;
  width: 100%;
  min-height: 500px;
  background: var(--nat-paper);
  border: 1px solid var(--nat-border);
  border-radius: 2px;
  box-shadow: 3px 4px 18px rgba(60,35,5,.18);
  font-family: var(--nat-serif);
  color: var(--nat-ink);
  container-type: inline-size;
  container-name: sp;
}

.sp-card .sp-photo-wrap {
  flex: 0 0 36%;
  position: relative;
  background: var(--nat-paper2);
  padding: 22px 16px 22px 22px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-right: 1px solid var(--nat-border);
  overflow: hidden;
}
.sp-card .sp-photo {
  max-width: 100%;
  max-height: 100%;
  width: 100%;
  object-fit: cover;
  display: block;
  filter: sepia(14%) contrast(96%) brightness(104%);
  padding: 7px;
  background: var(--nat-paper);
  box-shadow: 0 2px 10px rgba(60,35,5,.22), 0 0 0 1px var(--nat-border);
  box-sizing: border-box;
}
.sp-card .sp-photo-edge {
  position: absolute;
  inset: 0;
  pointer-events: none;
  box-shadow: inset -30px 0 50px -10px var(--nat-paper2);
}
.sp-card.no-photo .sp-photo-wrap { display: none; }

.sp-card .sp-page {
  flex: 1 1 auto;
  min-width: 0;
  padding: clamp(22px, 3vw, 44px) clamp(24px, 3.2vw, 52px);
  display: flex;
  flex-direction: column;
}

.sp-card .sp-sci-name {
  font-family: var(--nat-serif);
  font-size: clamp(1.6em, 2.7vw, 2.4em);
  font-weight: normal;
  font-style: italic;
  line-height: 1.1;
  color: var(--nat-ink);
  margin: 0 0 .18em;
}
.sp-card .sp-common {
  font-size: .98em;
  color: var(--nat-ink2);
  margin: 0 0 .6em;
  letter-spacing: .02em;
}
.sp-card .sp-common::after {
  content: '';
  display: block;
  margin-top: .6em;
  border-top: 1px solid var(--nat-border);
  border-bottom: 1px solid var(--nat-faint);
  height: 2px;
}
.sp-card .sp-breadcrumb {
  font-size: .68em;
  font-variant: small-caps;
  letter-spacing: .1em;
  color: var(--nat-muted);
  margin: .5em 0 .9em;
}
.sp-card .sp-sep { opacity: .5; }

.sp-card .sp-badges {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  margin: 0 0 1.3em;
}
.sp-badge {
  font-family: var(--nat-serif);
  font-size: .62em;
  font-weight: normal;
  letter-spacing: .18em;
  text-transform: uppercase;
  padding: 2px 9px;
  border-radius: 1px;
  border: 1px solid currentColor;
}
.sp-badge.iucn-lc { color: #2a5c2a; background: rgba(42,92,42,.08); }
.sp-badge.iucn-nt { color: #4a6a20; background: rgba(74,106,32,.08); }
.sp-badge.iucn-vu { color: #8b5a00; background: rgba(139,90,0,.08); }
.sp-badge.iucn-en { color: #8b2020; background: rgba(139,32,32,.08); }
.sp-badge.iucn-cr { color: #6a0020; background: rgba(106,0,32,.08); }
.sp-badge.iucn-ew { color: #4a0060; background: rgba(74,0,96,.08); }
.sp-badge.iucn-ex { color: #1a1a1a; background: rgba(26,26,26,.08); }
.sp-badge.iucn-dd { color: var(--nat-muted); background: transparent; }
.sp-badge.sp-rating { color: var(--nat-ink2); border-color: var(--nat-faint); background: transparent; }
.sp-badge.sp-seen   { color: var(--nat-green); border-color: var(--nat-green); background: rgba(61,92,53,.08); }

.sp-card .sp-section-label {
  font-family: var(--nat-serif);
  font-size: .7em;
  font-variant: small-caps;
  letter-spacing: .2em;
  color: var(--nat-muted);
  margin: 0 0 .5em;
  font-weight: normal;
}
.sp-card .sp-section-label::before,
.sp-card .sp-section-label::after {
  content: '4';
  margin: 0 5px;
  opacity: .35;
}

.sp-card .sp-info {
  font-size: .93em;
  line-height: 1.65;
  color: var(--nat-ink);
  margin-bottom: 1.1em;
}

.sp-card .sp-locations { margin-top: 1.2em; }
.sp-card .sp-locations.is-empty { display: none; }
.sp-card .sp-sightings {
  list-style: none;
  margin: 0;
  padding: 0;
  font-size: .87em;
  line-height: 1.6;
  color: var(--nat-ink2);
}
.sp-card .sp-sightings li {
  padding: 5px 0;
  border-bottom: 1px dashed var(--nat-border);
}
.sp-card .sp-sightings li:last-child { border-bottom: none; }
.sp-card .sp-sightings a { color: var(--nat-green); text-decoration: none; border-bottom: 1px dotted var(--nat-green); }
.sp-card .sp-sightings a:hover { border-bottom-style: solid; }

.sp-card .sp-related-wrap { margin-top: 1.3em; }
.sp-card .sp-related {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: .4em;
}
.sp-card .sp-related-item {
  width: 76px;
  cursor: pointer;
  text-align: center;
}
.sp-card .sp-related-frame {
  width: 76px;
  height: 76px;
  overflow: hidden;
  border: 1px solid var(--nat-border);
  padding: 3px;
  background: var(--nat-paper);
  box-sizing: border-box;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: border-color .15s;
}
.sp-card .sp-related-item:hover .sp-related-frame { border-color: var(--nat-green); }
.sp-card .sp-related-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  filter: sepia(14%) contrast(96%) brightness(104%);
}
.sp-card .sp-related-no-img {
  font-size: .65em;
  font-style: italic;
  color: var(--nat-muted);
}
.sp-card .sp-related-label {
  font-size: .58em;
  font-style: italic;
  color: var(--nat-muted);
  margin-top: 4px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 76px;
}

.sp-card .sp-footer {
  margin-top: auto;
  padding-top: .8em;
  border-top: 1px solid var(--nat-border);
  box-shadow: 0 -3px 0 0 var(--nat-faint);
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  font-size: .6em;
  letter-spacing: .22em;
  text-transform: uppercase;
  color: var(--nat-muted);
  font-style: italic;
}

@container sp (max-width: 680px) {
  .sp-card { flex-direction: column; min-height: 0; }
  .sp-card .sp-photo-wrap { flex: 0 0 auto; min-height: 260px; }
}
@media (max-width: 680px) {
  .sp-card { flex-direction: column; min-height: 0; }
  .sp-card .sp-photo-wrap { flex: 0 0 auto; min-height: 260px; }
}

