const _c = this;
(async () => {
  try {
    const root = _c.querySelector('.sp-card');
    if (!root) return;

    const wantName = root.dataset.name || '';
    let file = app.workspace.getActiveFile();
    if ((!file && wantName) || (file && wantName && file.name !== wantName)) {
      const byName = app.vault.getFiles().find(f => f.name === wantName);
      if (byName) file = byName;
    }
    if (!file) return;

    const fm    = (app.metadataCache.getFileCache(file) || {}).frontmatter || {};
    const clean = s => String(s == null ? '' : s).replace(/\[\[|\]\]/g, '').trim();

    let raw = await app.vault.cachedRead(file);
    raw = raw.replace(/^---\s*\n[\s\S]*?\n---\s*\n?/, '');

    // --- Photo ---
    const img     = root.querySelector('#spImg');
    const wikiImg = raw.match(/!\[\[([^\]|#\n]+)/);
    if (wikiImg) {
      const dest = app.metadataCache.getFirstLinkpathDest(wikiImg[1].trim(), file.path);
      if (dest) img.src = app.vault.getResourcePath(dest);
      else root.classList.add('no-photo');
    } else root.classList.add('no-photo');

    // --- Scientific name ---
    const sciEl = root.querySelector('.sp-sci-name');
    if (sciEl) {
      const g = clean(fm.genus || ''), s = clean(fm.species || '');
      sciEl.innerHTML = `<em>${g}${g && s ? ' ' : ''}${s}</em>`;
    }

    // --- Common name ---
    const commonEl = root.querySelector('.sp-common');
    if (commonEl) {
      if (fm['common name']) commonEl.textContent = clean(fm['common name']);
      else commonEl.style.display = 'none';
    }

    // --- Taxonomy breadcrumb ---
    const breadEl = root.querySelector('.sp-breadcrumb');
    if (breadEl) {
      const parts = ['kingdom','phylum','class','order','family']
        .map(r => clean(fm[r] || '')).filter(Boolean);
      breadEl.innerHTML = ['Eukaryota'].concat(parts)
        .map(name => `<a class="internal-link" data-href="${name}/${name}">${name}</a>`)
        .join('<span class="sp-sep"> › </span>');
    }

    // --- Badges ---
    const badgesEl = root.querySelector('.sp-badges');
    if (badgesEl) {
      const iucnMap = {
        'Least Concern':['LC','iucn-lc'],'LC':['LC','iucn-lc'],
        'Near Threatened':['NT','iucn-nt'],'NT':['NT','iucn-nt'],
        'Vulnerable':['VU','iucn-vu'],'VU':['VU','iucn-vu'],
        'Endangered':['EN','iucn-en'],'EN':['EN','iucn-en'],
        'Critically Endangered':['CR','iucn-cr'],'CR':['CR','iucn-cr'],
        'Extinct in the Wild':['EW','iucn-ew'],'EW':['EW','iucn-ew'],
        'Extinct':['EX','iucn-ex'],'EX':['EX','iucn-ex'],
      };
      const html = [];
      const iucnRaw = clean(fm['IUCN red list'] || '');
      if (iucnRaw) {
        const [abbr, cls] = iucnMap[iucnRaw] || [iucnRaw, 'iucn-dd'];
        html.push(`<span class="sp-badge sp-iucn ${cls}">${abbr}</span>`);
      }
      if (typeof fm.rating === 'number')
        html.push(`<span class="sp-badge sp-rating">★ ${fm.rating}/10</span>`);
      if (fm.seen === true)
        html.push(`<span class="sp-badge sp-seen">● Seen</span>`);
      badgesEl.innerHTML = html.join('');
    }

    // --- Sightings ---
    const toHtml = line => {
      line = line.replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, t, a) =>
        `<a class="internal-link" data-href="${t}">${a || t}</a>`);
      line = line.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (_, txt, url) =>
        `<a href="${url}" target="_blank" rel="noopener">${txt}</a>`);
      return line;
    };
    const sightingsEl  = root.querySelector('.sp-sightings');
    const locContainer = root.querySelector('.sp-locations');
    const locMatch     = raw.match(/^#+\s+Locations?\s+Seen\s*\r?\n([\s\S]*?)(?=\n#+\s|$)/im);
    if (locMatch && locMatch[1].trim() && sightingsEl) {
      locMatch[1].trim().split(/\r?\n/).filter(l => l.trim()).forEach(line => {
        const li = document.createElement('li');
        li.innerHTML = toHtml(line.trim());
        sightingsEl.appendChild(li);
      });
      if (!sightingsEl.children.length) locContainer.classList.add('is-empty');
    } else if (locContainer) locContainer.classList.add('is-empty');

    // --- Congeners ---
    const relatedWrap = root.querySelector('.sp-related-wrap');
    const genus = clean(fm.genus || '');
    if (relatedWrap && genus) {
      const siblings = app.vault.getFiles().filter(f =>
        f.extension === 'md' &&
        f.basename !== file.basename &&
        f.basename.toLowerCase().startsWith(genus.toLowerCase() + ' ')
      );
      if (siblings.length > 0) {
        const lbl = document.createElement('p');
        lbl.className = 'sp-section-label';
        lbl.innerHTML = `<em>${genus}</em> congeners`;
        relatedWrap.appendChild(lbl);

        const grid = document.createElement('div');
        grid.className = 'sp-related';
        relatedWrap.appendChild(grid);

        for (const sf of siblings) {
          const imgBase = sf.basename.replace(/ /g, '_');
          const sibDest = app.metadataCache.getFirstLinkpathDest(imgBase + '.jpg', sf.path)
                       || app.metadataCache.getFirstLinkpathDest(imgBase + '.png', sf.path);

          const item = document.createElement('div');
          item.className = 'sp-related-item';
          item.title = sf.basename;

          const frame = document.createElement('div');
          frame.className = 'sp-related-frame';
          if (sibDest) {
            const thumb = document.createElement('img');
            thumb.src = app.vault.getResourcePath(sibDest);
            thumb.className = 'sp-related-img';
            frame.appendChild(thumb);
          } else {
            frame.classList.add('sp-related-no-img');
            frame.textContent = sf.basename.split(' ').slice(1).join(' ').slice(0,4) + '.';
          }
          item.appendChild(frame);

          const epithet = document.createElement('div');
          epithet.className = 'sp-related-label';
          epithet.textContent = sf.basename.split(' ').slice(1).join(' ');
          item.appendChild(epithet);

          item.addEventListener('click', () =>
            app.workspace.openLinkText(sf.basename, file.path, false));
          grid.appendChild(item);
        }
      } else relatedWrap.style.display = 'none';
    } else if (relatedWrap) relatedWrap.style.display = 'none';

    // --- Footer ---
    const footer = root.querySelector('.sp-footer');
    if (footer) {
      const left  = clean(fm.kingdom || '');
      const right = `${clean(fm.genus || '')} ${clean(fm.species || '')}`.trim();
      footer.innerHTML = `<span>${left}</span><span class="sp-footer-sci"><em>${right}</em></span>`;
    }

    // --- Wire internal links ---
    root.querySelectorAll('a.internal-link').forEach(a => {
      const href = a.dataset.href || a.getAttribute('href');
      if (!href) return;
      a.addEventListener('click', e => {
        e.preventDefault();
        app.workspace.openLinkText(href, file.path, e.ctrlKey || e.metaKey);
      });
    });

  } catch(e) { console.error('[Custom Views: Species]', e); }
})();

