    // --- Common name ---
    const commonEl = root.querySelector('.fam-common');
    if (commonEl) {
      if (fm['common name']) commonEl.textContent = clean(fm['common name']);
      else commonEl.style.display = 'none';
    }

    // --- Breadcrumb ---
    const breadEl = root.querySelector('.fam-breadcrumb');
    if (breadEl) {
      const parts = ['kingdom','phylum','class','order','family']
        .map(r => clean(fm[r] || '')).filter(Boolean);
      breadEl.innerHTML = ['Eukaryota'].concat(parts)
        .map(name => `<a class="internal-link" data-href="${name}/${name}">${name}</a>`)
        .join('<span class="fam-sep"> › </span>');
    }

    // --- Collect species in this family ---
    const familyName = clean(fm.family || '');
    const genera = {};
    let seenCount = 0, totalCount = 0;
    if (familyName) {
      for (const sf of app.vault.getFiles()) {
        if (sf.extension !== 'md' || sf.path === file.path) continue;
        const sfm = (app.metadataCache.getFileCache(sf) || {}).frontmatter;
        if (!sfm || sfm.theme !== 'nature' || clean(sfm.family || '') !== familyName) continue;
        totalCount++;
        if (sfm.seen === true) seenCount++;
        const g = clean(sfm.genus || '');
        if (g) {
          if (!genera[g]) genera[g] = [];
          genera[g].push({ file: sf, fm: sfm });
        }
      }
    }
    const generaNames = Object.keys(genera);

    // --- Badges ---
    const badgesEl = root.querySelector('.fam-badges');
    if (badgesEl) {
      const html = [];
      if (totalCount > 0)
        html.push(`<span class="fam-badge fam-count">${totalCount} species · ${generaNames.length} ${generaNames.length === 1 ? 'genus' : 'genera'}</span>`);
      if (seenCount > 0)
        html.push(`<span class="fam-badge fam-seen">● ${seenCount} seen</span>`);
      badgesEl.innerHTML = html.join('');
    }

    // --- Description ---
    const descEl = root.querySelector('.fam-description');
    if (descEl) {
      const infoMatch = raw.match(/#+\s+Info\s*\r?\n([\s\S]*?)(?=\n#+\s|\n*$)/i);
      if (infoMatch) {
        const lines = infoMatch[1].split(/\r?\n/);
        const descLine = lines.find(l => l.trim() && !l.trim().startsWith('![['));
        if (descLine) descEl.textContent = descLine.trim();
      }
    }

    // --- Genus strip ---
    const generaWrap = root.querySelector('.fam-genera-wrap');
    const generaGrid = root.querySelector('.fam-genera');
    if (generaWrap && generaGrid && generaNames.length > 0) {
      for (const g of generaNames.sort()) {
        const members = genera[g];
        members.sort((a, b) => {
          const aS = a.fm.seen === true ? 0 : 1;
          const bS = b.fm.seen === true ? 0 : 1;
          if (aS !== bS) return aS - bS;
          return a.file.basename.localeCompare(b.file.basename);
        });
        const rep = members[0];
        const imgBase = rep.file.basename.replace(/ /g, '_');
        const imgDest = app.metadataCache.getFirstLinkpathDest(imgBase + '.jpg', rep.file.path)
                     || app.metadataCache.getFirstLinkpathDest(imgBase + '.png', rep.file.path);

        const item  = document.createElement('div');
        item.className = 'fam-genus-item';
        item.title = g;

        const frame = document.createElement('div');
        frame.className = 'fam-genus-frame';
        if (imgDest) {
          const thumb = document.createElement('img');
          thumb.src = app.vault.getResourcePath(imgDest);
          thumb.className = 'fam-genus-img';
          frame.appendChild(thumb);
        } else {
          frame.classList.add('fam-genus-no-img');
          frame.textContent = g.slice(0, 4) + '.';
        }
        item.appendChild(frame);

        const lbl = document.createElement('div');
        lbl.className = 'fam-genus-label';
        lbl.textContent = g;
        item.appendChild(lbl);

        item.addEventListener('click', () =>
          app.workspace.openLinkText(rep.file.basename, file.path, false));
        generaGrid.appendChild(item);
      }
    } else if (generaWrap) generaWrap.style.display = 'none';

    // --- Footer ---
    const footer = root.querySelector('.fam-footer');
    if (footer) {
      footer.innerHTML = `<span>${clean(fm.kingdom || '')}</span><span><em>${clean(fm.family || '')}</em></span>`;
    }

  } catch(e) { console.error('[Custom Views: Family]', e); }
})();

