const _c = this;
(async () => {
  try {
    const root = _c.querySelector('.eur-card');
    if (!root) return;

    const wantName = root.dataset.name || '';
    let file = app.workspace.getActiveFile();
    if ((!file && wantName) || (file && wantName && file.name !== wantName)) {
      const byName = app.vault.getFiles().find(f => f.name === wantName);
      if (byName) file = byName;
    }
    if (!file) return;

    const fm    = (app.metadataCache.getFileCache(file) || {}).frontmatter || {};
    const clean = s => String(s == null ? '' : s).replace(/\[\[|\]\]/g, '').trim();

    let raw = await app.vault.cachedRead(file);
    raw = raw.replace(/^---\s*\n[\s\S]*?\n---\s*\n?/, '');

    // Photo
    const img = root.querySelector('#eurImg');
    const wikiImg = raw.match(/!\[\[([^\]|#\n]+)/);
    if (wikiImg) {
      const dest = app.metadataCache.getFirstLinkpathDest(wikiImg[1].trim(), file.path);
      if (dest) img.src = app.vault.getResourcePath(dest);
      else root.classList.add('no-photo');
    } else root.classList.add('no-photo');

    // Title
    const sciEl = root.querySelector('.eur-sci-name');
    if (sciEl) sciEl.innerHTML = `<em>${file.basename}</em>`;

    // Common name
    const commonEl = root.querySelector('.eur-common');
    if (commonEl) {
      if (fm['common name']) commonEl.textContent = clean(fm['common name']);
      else commonEl.style.display = 'none';
    }

    // Scan all species notes for counts
    const kingdoms = new Set();
    const families = new Set();
    let totalCount = 0, seenCount = 0;
    for (const sf of app.vault.getFiles()) {
      if (sf.extension !== 'md' || sf.path === file.path) continue;
      const sfm = (app.metadataCache.getFileCache(sf) || {}).frontmatter;
      if (!sfm || sfm.theme !== 'nature') continue;
      totalCount++;
      if (sfm.seen === true) seenCount++;
      const kin = clean(sfm.kingdom || '');
      if (kin) kingdoms.add(kin);
      const fam = clean(sfm.family || '');
      if (fam) families.add(fam);
    }

    // Badges
    const badgesEl = root.querySelector('.eur-badges');
    if (badgesEl) {
      const kinWord = kingdoms.size === 1 ? 'kingdom' : 'kingdoms';
      const famWord = families.size === 1 ? 'family' : 'families';
      const html = [`<span class="eur-badge eur-count">${kingdoms.size} ${kinWord} · ${families.size} ${famWord} · ${totalCount} species</span>`];
      if (seenCount > 0) html.push(`<span class="eur-badge eur-seen">● ${seenCount} seen</span>`);
      badgesEl.innerHTML = html.join('');
    }

    // Description
    const descEl = root.querySelector('.eur-description');
    if (descEl) {
      const infoMatch = raw.match(/#+\s+Info\s*\r?\n([\s\S]*?)(?=\n#+\s|\n*$)/i);
      if (infoMatch) {
        const lines = infoMatch[1].split(/\r?\n/);
        const descLine = lines.find(l => l.trim() && !l.trim().startsWith('![['));
        if (descLine) descEl.textContent = descLine.trim();
      }
    }

    // Kingdom strip
    const stripWrap = root.querySelector('.eur-strip-wrap');
    const strip = root.querySelector('.eur-strip');
    if (strip && kingdoms.size > 0) {
      for (const kinName of [...kingdoms].sort()) {
        const imgDest = app.metadataCache.getFirstLinkpathDest(kinName + '.jpg', file.path);
        const item = document.createElement('div');
        item.className = 'eur-strip-item';
        item.title = kinName;
        const frame = document.createElement('div');
        frame.className = 'eur-strip-frame';
        if (imgDest) {
          const thumb = document.createElement('img');
          thumb.src = app.vault.getResourcePath(imgDest);
          thumb.className = 'eur-strip-img';
          frame.appendChild(thumb);
        } else {
          frame.classList.add('eur-strip-no-img');
          frame.textContent = kinName.slice(0, 4) + '.';
        }
        item.appendChild(frame);
        const lbl = document.createElement('div');
        lbl.className = 'eur-strip-label';
        lbl.textContent = kinName;
        item.appendChild(lbl);
        item.addEventListener('click', () => app.workspace.openLinkText(kinName + '/' + kinName, file.path, false));
        strip.appendChild(item);
      }
    } else if (stripWrap) stripWrap.style.display = 'none';

    // Footer
    const footer = root.querySelector('.eur-footer');
    if (footer) {
      footer.innerHTML = `<span></span><span><em>${file.basename}</em></span>`;
    }

  } catch(e) { console.error('[Custom Views: Eukaryota]', e); }
})();

