      if (fm['common name']) commonEl.textContent = clean(fm['common name']);
      else commonEl.style.display = 'none';
    }

    const breadEl = root.querySelector('.phy-breadcrumb');
    if (breadEl) {
      const parts = ['kingdom','phylum']
        .map(r => clean(fm[r] || '')).filter(Boolean);
      breadEl.innerHTML = ['Eukaryota'].concat(parts)
        .map(name => `<a class="internal-link" data-href="${name}/${name}">${name}</a>`)
        .join('<span class="phy-sep"> › </span>');
    }

    const phylumName = clean(fm.phylum || '');
    const classes = new Set();
    const families = new Set();
    let totalCount = 0, seenCount = 0;
    if (phylumName) {
      for (const sf of app.vault.getFiles()) {
        if (sf.extension !== 'md' || sf.path === file.path) continue;
        const sfm = (app.metadataCache.getFileCache(sf) || {}).frontmatter;
        if (!sfm || sfm.theme !== 'nature' || clean(sfm.phylum || '') !== phylumName) continue;
        totalCount++;
        if (sfm.seen === true) seenCount++;
        const cls = clean(sfm.class || '');
        if (cls) classes.add(cls);
        const fam = clean(sfm.family || '');
        if (fam) families.add(fam);
      }
    }

    const badgesEl = root.querySelector('.phy-badges');
    if (badgesEl) {
      const clsWord = classes.size === 1 ? 'class' : 'classes';
      const famWord = families.size === 1 ? 'family' : 'families';
      const html = [`<span class="phy-badge phy-count">${classes.size} ${clsWord} · ${families.size} ${famWord} · ${totalCount} species</span>`];
      if (seenCount > 0) html.push(`<span class="phy-badge phy-seen">● ${seenCount} seen</span>`);
      badgesEl.innerHTML = html.join('');
    }

    const descEl = root.querySelector('.phy-description');
    if (descEl) {
      const infoMatch = raw.match(/#+\s+Info\s*\r?\n([\s\S]*?)(?=\n#+\s|\n*$)/i);
      if (infoMatch) {
        const lines = infoMatch[1].split(/\r?\n/);
        const descLine = lines.find(l => l.trim() && !l.trim().startsWith('![['));
        if (descLine) descEl.textContent = descLine.trim();
      }
    }

    const stripWrap = root.querySelector('.phy-strip-wrap');
    const strip = root.querySelector('.phy-strip');
    if (strip && classes.size > 0) {
      for (const clsName of [...classes].sort()) {
        const imgDest = app.metadataCache.getFirstLinkpathDest(clsName + '.jpg', file.path);
        const item = document.createElement('div');
        item.className = 'phy-strip-item';
        item.title = clsName;
        const frame = document.createElement('div');
        frame.className = 'phy-strip-frame';
        if (imgDest) {
          const thumb = document.createElement('img');
          thumb.src = app.vault.getResourcePath(imgDest);
          thumb.className = 'phy-strip-img';
          frame.appendChild(thumb);
        } else {
          frame.classList.add('phy-strip-no-img');
          frame.textContent = clsName.slice(0, 4) + '.';
        }
        item.appendChild(frame);
        const lbl = document.createElement('div');
        lbl.className = 'phy-strip-label';
        lbl.textContent = clsName;
        item.appendChild(lbl);
        item.addEventListener('click', () => app.workspace.openLinkText(clsName + '/' + clsName, file.path, false));
        strip.appendChild(item);
      }
    } else if (stripWrap) stripWrap.style.display = 'none';

    const footer = root.querySelector('.phy-footer');
    if (footer) {
      footer.innerHTML = `<span>${clean(fm.kingdom || '')}</span><span><em>${clean(fm.phylum || '')}</em></span>`;
    }

    root.querySelectorAll('a.internal-link').forEach(a => {
      const href = a.dataset.href || a.getAttribute('href');
      if (!href) return;
      a.addEventListener('click', e => {
        e.preventDefault();
        app.workspace.openLinkText(href, file.path, e.ctrlKey || e.metaKey);
      });
    });

  } catch(e) { console.error('[Custom Views: Phylum]', e); }
})();

views.css:
.kin-card {
  --nat-ink:    #1e1508;
  --nat-ink2:   #5c4a2c;
  --nat-muted:  #8c7a5a;
  --nat-faint:  #b5a47a;
  --nat-paper:  #f4eed7;
  --nat-paper2: #e8dfc4;
  --nat-border: #c4aa7a;
  --nat-green:  #3d5c35;
  --nat-serif:  'Palatino Linotype', Palatino, 'Book Antiqua', Georgia, serif;

  display: flex;
  align-items: stretch;
  width: 100%;
  min-height: 500px;
  background: var(--nat-paper);
  border: 1px solid var(--nat-border);
  border-radius: 2px;
  box-shadow: 3px 4px 18px rgba(60,35,5,.18);
  font-family: var(--nat-serif);
  color: var(--nat-ink);
  container-type: inline-size;
  container-name: kin;
}

.kin-card .kin-photo-wrap {
  flex: 0 0 36%;
  position: relative;
  background: var(--nat-paper2);
  padding: 22px 16px 22px 22px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-right: 1px solid var(--nat-border);
  overflow: hidden;
}
.kin-card .kin-photo {
  max-width: 100%;
  max-height: 100%;
  width: 100%;
  object-fit: cover;
  display: block;
  filter: sepia(14%) contrast(96%) brightness(104%);
  padding: 7px;
  background: var(--nat-paper);
  box-shadow: 0 2px 10px rgba(60,35,5,.22), 0 0 0 1px var(--nat-border);
  box-sizing: border-box;
}
.kin-card .kin-photo-edge {
  position: absolute;
  inset: 0;
  pointer-events: none;
  box-shadow: inset -30px 0 50px -10px var(--nat-paper2);
}
.kin-card.no-photo .kin-photo-wrap { display: none; }

.kin-card .kin-page {
  flex: 1 1 auto;
  min-width: 0;
  padding: clamp(22px, 3vw, 44px) clamp(24px, 3.2vw, 52px);
  display: flex;
  flex-direction: column;
}

.kin-card .kin-sci-name {
  font-family: var(--nat-serif);
  font-size: clamp(1.6em, 2.7vw, 2.4em);
  font-weight: normal;
  font-style: italic;
  line-height: 1.1;
  color: var(--nat-ink);
  margin: 0 0 .18em;
}
.kin-card .kin-common {
  font-size: .98em;
  color: var(--nat-ink2);
  margin: 0 0 .6em;
  letter-spacing: .02em;
}
.kin-card .kin-common::after {
  content: '';
  display: block;
  margin-top: .6em;
  border-top: 1px solid var(--nat-border);
  border-bottom: 1px solid var(--nat-faint);
  height: 2px;
}
.kin-card .kin-breadcrumb {
  font-size: .68em;
  font-variant: small-caps;
  letter-spacing: .1em;
  color: var(--nat-muted);
  margin: .5em 0 .9em;
}
.kin-card .kin-breadcrumb:empty { display: none; }
.kin-card .kin-sep { opacity: .5; }

.kin-card .kin-badges {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  margin: 0 0 1.1em;
}
.kin-badge {
  font-family: var(--nat-serif);
  font-size: .62em;
  font-weight: normal;
  letter-spacing: .18em;
  text-transform: uppercase;
  padding: 2px 9px;
  border-radius: 1px;
  border: 1px solid currentColor;
}
.kin-badge.kin-count { color: var(--nat-ink2); border-color: var(--nat-faint); background: transparent; }
.kin-badge.kin-seen  { color: var(--nat-green); border-color: var(--nat-green); background: rgba(61,92,53,.08); }

.kin-card .kin-description {
  font-size: .93em;
  line-height: 1.65;
  color: var(--nat-ink);
  font-style: italic;
  margin-bottom: 1.3em;
  padding-bottom: 1.1em;
  border-bottom: 1px dashed var(--nat-border);
}
.kin-card .kin-description:empty { display: none; }

.kin-card .kin-section-label {
  font-family: var(--nat-serif);
  font-size: .7em;
  font-variant: small-caps;
  letter-spacing: .2em;
  color: var(--nat-muted);
  margin: 0 0 .5em;
  font-weight: normal;
}
.kin-card .kin-section-label::before,
.kin-card .kin-section-label::after {
  content: '4';
  margin: 0 5px;
  opacity: .35;
}

.kin-card .kin-strip-wrap { margin-top: .3em; }
.kin-card .kin-strip {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: .4em;
}
.kin-card .kin-strip-item {
  width: 76px;
  cursor: pointer;
  text-align: center;
}
.kin-card .kin-strip-frame {
  width: 76px;
  height: 76px;
  overflow: hidden;
  border: 1px solid var(--nat-border);
  padding: 3px;
  background: var(--nat-paper);
  box-sizing: border-box;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: border-color .15s;
}
.kin-card .kin-strip-item:hover .kin-strip-frame { border-color: var(--nat-green); }
.kin-card .kin-strip-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  filter: sepia(14%) contrast(96%) brightness(104%);
}
.kin-card .kin-strip-no-img {
  font-size: .65em;
  font-style: italic;
  color: var(--nat-muted);
}
.kin-card .kin-strip-label {
  font-size: .58em;
  font-style: italic;
  color: var(--nat-muted);
  margin-top: 4px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 76px;
}

.kin-card .kin-footer {
  margin-top: auto;
  padding-top: .8em;
  border-top: 1px solid var(--nat-border);
  box-shadow: 0 -3px 0 0 var(--nat-faint);
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  font-size: .6em;
  letter-spacing: .22em;
  text-transform: uppercase;
  color: var(--nat-muted);
  font-style: italic;
}

@container kin (max-width: 680px) {
  .kin-card { flex-direction: column; min-height: 0; }
  .kin-card .kin-photo-wrap { flex: 0 0 auto; min-height: 260px; }
}
@media (max-width: 680px) {
  .kin-card { flex-direction: column; min-height: 0; }
  .kin-card .kin-photo-wrap { flex: 0 0 auto; min-height: 260px; }
}

