const _c = this;
(async () => {
  try {
    const root = _c.querySelector('.kin-card');
    if (!root) return;

    const wantName = root.dataset.name || '';
    let file = app.workspace.getActiveFile();
    if ((!file && wantName) || (file && wantName && file.name !== wantName)) {
      const byName = app.vault.getFiles().find(f => f.name === wantName);
      if (byName) file = byName;
    }
    if (!file) return;

    const fm    = (app.metadataCache.getFileCache(file) || {}).frontmatter || {};
    const clean = s => String(s == null ? '' : s).replace(/\[\[|\]\]/g, '').trim();

    let raw = await app.vault.cachedRead(file);
    raw = raw.replace(/^---\s*\n[\s\S]*?\n---\s*\n?/, '');

    const img = root.querySelector('#kinImg');
    const wikiImg = raw.match(/!\[\[([^\]|#\n]+)/);
    if (wikiImg) {
      const dest = app.metadataCache.getFirstLinkpathDest(wikiImg[1].trim(), file.path);
      if (dest) img.src = app.vault.getResourcePath(dest);
      else root.classList.add('no-photo');
    } else root.classList.add('no-photo');

    const sciEl = root.querySelector('.kin-sci-name');
    if (sciEl) sciEl.innerHTML = `<em>${clean(fm.kingdom || '')}</em>`;

    const commonEl = root.querySelector('.kin-common');
    if (commonEl) {
      if (fm['common name']) commonEl.textContent = clean(fm['common name']);
      else commonEl.style.display = 'none';
    }

    const breadEl = root.querySelector('.kin-breadcrumb');
    if (breadEl) {
      breadEl.innerHTML = '<a class="internal-link" data-href="Eukaryota/Eukaryota">Eukaryota</a>';
    }

    const kingdomName = clean(fm.kingdom || '');
    const phyla = new Set();
    const families = new Set();
    let totalCount = 0, seenCount = 0;
    if (kingdomName) {
      for (const sf of app.vault.getFiles()) {
        if (sf.extension !== 'md' || sf.path === file.path) continue;
        const sfm = (app.metadataCache.getFileCache(sf) || {}).frontmatter;
        if (!sfm || sfm.theme !== 'nature' || clean(sfm.kingdom || '') !== kingdomName) continue;
        totalCount++;
        if (sfm.seen === true) seenCount++;
        const phy = clean(sfm.phylum || '');
        if (phy) phyla.add(phy);
        const fam = clean(sfm.family || '');
        if (fam) families.add(fam);
      }
    }

    const badgesEl = root.querySelector('.kin-badges');
    if (badgesEl) {
      const phyWord = phyla.size === 1 ? 'phylum' : 'phyla';
      const famWord = families.size === 1 ? 'family' : 'families';
      const html = [`<span class="kin-badge kin-count">${phyla.size} ${phyWord} · ${families.size} ${famWord} · ${totalCount} species</span>`];
      if (seenCount > 0) html.push(`<span class="kin-badge kin-seen">● ${seenCount} seen</span>`);
      badgesEl.innerHTML = html.join('');
    }

    const descEl = root.querySelector('.kin-description');
    if (descEl) {
      const infoMatch = raw.match(/#+\s+Info\s*\r?\n([\s\S]*?)(?=\n#+\s|\n*$)/i);
      if (infoMatch) {
        const lines = infoMatch[1].split(/\r?\n/);
        const descLine = lines.find(l => l.trim() && !l.trim().startsWith('![['));
        if (descLine) descEl.textContent = descLine.trim();
      }
    }

    const stripWrap = root.querySelector('.kin-strip-wrap');
    const strip = root.querySelector('.kin-strip');
    if (strip && phyla.size > 0) {
      for (const phyName of [...phyla].sort()) {
        const imgDest = app.metadataCache.getFirstLinkpathDest(phyName + '.jpg', file.path);
        const item = document.createElement('div');
        item.className = 'kin-strip-item';
        item.title = phyName;
        const frame = document.createElement('div');
        frame.className = 'kin-strip-frame';
        if (imgDest) {
          const thumb = document.createElement('img');
          thumb.src = app.vault.getResourcePath(imgDest);
          thumb.className = 'kin-strip-img';
          frame.appendChild(thumb);
        } else {
          frame.classList.add('kin-strip-no-img');
          frame.textContent = phyName.slice(0, 4) + '.';
        }
        item.appendChild(frame);
        const lbl = document.createElement('div');
        lbl.className = 'kin-strip-label';
        lbl.textContent = phyName;
        item.appendChild(lbl);
        item.addEventListener('click', () => app.workspace.openLinkText(phyName + '/' + phyName, file.path, false));
        strip.appendChild(item);
      }
    } else if (stripWrap) stripWrap.style.display = 'none';

    const footer = root.querySelector('.kin-footer');
    if (footer) {
      footer.innerHTML = `<span></span><span><em>${clean(fm.kingdom || '')}</em></span>`;
    }

    root.querySelectorAll('a.internal-link').forEach(a => {
      const href = a.dataset.href || a.getAttribute('href');
      if (!href) return;
      a.addEventListener('click', e => {
        e.preventDefault();
        app.workspace.openLinkText(href, file.path, e.ctrlKey || e.metaKey);
      });
    });

  } catch(e) { console.error('[Custom Views: Kingdom]', e); }
})();
